image.asymptote:
import graph;
size(200,IgnoreAspect);

real f(real x) {return x^2;}

draw(graph(f,-2,2), deepblue);

dot((-2,f(-2)), red);
draw((-2,0)--(-2,f(-2)), red+dashed);
dot((-1,f(-1)), red);
draw((-1,0)--(-1,f(-1)), red+dashed);
dot((-.5,f(-.5)), red);
draw((-.5,0)--(-.5,f(-.5)), red+dashed);

yaxis("$y$",ymin=-.1,ymax=f(2.1),RightTicks(Label(Fill(white))),EndArrow);
xaxis("$x$",xmin=-5,xmax=5,LeftTicks,EndArrow);

statement.p:
Let f(x) be given by
f(x) = \begin{cases} 0 & -3\leq x \leq -1 \\ x^{2} & -1 < x < \frac{1}{2} \\ \frac{1-x}{2} & \frac{1}{2} < x < 3. \end{cases} 
Evaluate \lim_{x\to-1}f(x) and \lim_{x\to\frac{1}{2}}f(x).

image.latex-image-code:
\pgfmathdeclarefunction{MyFunction}{1}{%
  \pgfmathparse{%
    (and(   1,    #1<-1)*(0)            +%
    (and(#1>=-1,  #1< .5)*(#1*#1)   +%
    (and(#1>= .5,  #1< 3)*(.5-0.5*#1)%
    }%
}
\begin{tikzpicture}
    \begin{axis}[%
        axis x line = center,
        axis y line = center,
        xtick={-3,...,3},
        ytick={-3,...,3},
        xmin = -4,
        xmax = 4,
        ymin = -1.5,
        ymax = 1.5,
        xlabel={$x$},
        ylabel={$y$},
        grid=both
        ]
        \foreach \xStart/\xEnd  in {-3/-1, -1/.5, .5/3} {
        \addplot[domain=\xStart:\xEnd, blue, samples=10, ultra thick] {MyFunction(x)};
        }
        \addplot[incl] coordinates{(-3,0)};
        \addplot[incl] coordinates{(-1,0)};
        \addplot[excl] coordinates{(-1,1)};
        \addplot[excl] coordinates{(.5,.25)};
        \addplot[excl] coordinates{(3,-1)};
        \addlegendentry{$y = f(x)$};
    \end{axis}
\end{tikzpicture}
